10	export const createQueryHash = (parameters: QueryParameter[]): QueryHash => {
11	    sortedIDs.fill(0);
12	    let cursor = 0;
13	
14	    for (let i = 0; i < parameters.length; i++) {
15	        const param = parameters[i];
16	
17	        if (isRelationPair(param)) {
