import type { QueryInstance, QueryUnsubscriber } from '../query/types';
import type { World } from '../world';
import { hasAspect } from './aspect';
import type { Aspect } from './types';

export type AspectEventType = 'add' | 'remove' | 'change';
type AspectCallback = (entity: Entity) => void;

export interface AspectState {
    aspect: Aspect;
    /** Entities that currently have every constituent trait. */
    completeSet: Set<Entity>;
    onAdd: Set<AspectCallback>;
    onRemove: Set<AspectCallback>;
    onChange: Set<AspectCallback>;
    addedQueries: Set<QueryInstance>;
    removedQueries: Set<QueryInstance>;
    changedQueries: Set<QueryInstance>;
}

/**
 * Lazily create (and wire up) the per-world tracking state for an aspect.
 *
 * Attaches subscriptions to each constituent trait so that completeness
 * transitions can be detected and forwarded to lifecycle hooks and tracking
 * queries.
 */
export function getAspectState(world: World, aspect: Aspect): AspectState {
    const ctx = world[$internal];
    const existing = ctx.aspectStates.get(aspect.id);
    if (existing) return existing;

    const state: AspectState = {
        aspect,
        completeSet: new Set<Entity>(),
        onAdd: new Set(),
        onRemove: new Set(),
        onChange: new Set(),
        addedQueries: new Set(),
        removedQueries: new Set(),
        changedQueries: new Set(),
    };
    ctx.aspectStates.set(aspect.id, state);

    const onConstituentAdd = (entity: Entity) => {
        if (state.completeSet.has(entity)) return;
        if (!hasAspect(world, entity, aspect)) return;
        state.completeSet.add(entity);
        for (const cb of state.onAdd) cb(entity);
        for (const query of state.addedQueries) accumulate(world, query, entity);
    };

    const onConstituentRemove = (entity: Entity) => {
        // Fires before the trait bit is cleared, so a complete entity here is
        // transitioning to incomplete.
        if (!state.completeSet.has(entity)) return;
        state.completeSet.delete(entity);
        for (const cb of state.onRemove) cb(entity);
        for (const query of state.removedQueries) accumulate(world, query, entity);
    };

    const onConstituentChange = (entity: Entity) => {
        if (!state.completeSet.has(entity)) return;
        for (const cb of state.onChange) cb(entity);
        for (const query of state.changedQueries) accumulate(world, query, entity);
    };

    for (const trait of aspect.traits) {
        if (!hasTraitInstance(ctx.traitInstances, trait)) registerTrait(world, trait);
        const instance = getTraitInstance(ctx.traitInstances, trait)!;
        instance.addSubscriptions.add(onConstituentAdd);
        instance.removeSubscriptions.add(onConstituentRemove);
        instance.changeSubscriptions.add(onConstituentChange);
        // Ensure updateEach's auto change detection commits changes for these
        // traits so aspect change tracking fires.
        ctx.trackedTraits.add(trait);
    }

    // Seed with entities that are already complete so change tracking works for
    // pre-existing entities.
    for (const entity of world.entities) {
        if (hasAspect(world, entity, aspect)) state.completeSet.add(entity);
    }

    return state;
}

/** Add an entity to a tracking query if it satisfies the query's other constraints. */
function accumulate(world: World, query: QueryInstance, entity: Entity): void {
    if (!query.aspectTrackOnly) {
        if (!query.check(world, entity)) return;

        if (query.relationFilters && query.relationFilters.length > 0) {
            for (const pair of query.relationFilters) {
                if (!hasRelationPair(world, entity, pair)) return;
            }
        }

        if (query.aspectNot && query.aspectNot.length > 0) {
            for (const aspect of query.aspectNot) {
                if (hasAspect(world, entity, aspect)) return;
            }
        }
    }

    query.add(entity);
}

export function onAddAspect(
    world: World,
    aspect: Aspect,
    callback: AspectCallback
): QueryUnsubscriber {
    const state = getAspectState(world, aspect);
    state.onAdd.add(callback);
    return () => state.onAdd.delete(callback);
}

export function onRemoveAspect(
    world: World,
    aspect: Aspect,
    callback: AspectCallback
): QueryUnsubscriber {
    const state = getAspectState(world, aspect);
    state.onRemove.add(callback);
    return () => state.onRemove.delete(callback);
}

export function onChangeAspect(
    world: World,
    aspect: Aspect,
    callback: AspectCallback
): QueryUnsubscriber {
    const state = getAspectState(world, aspect);
    state.onChange.add(callback);
    return () => state.onChange.delete(callback);
}

export function registerAspectTrackingQuery(
    world: World,
    aspect: Aspect,
    type: AspectEventType,
    query: QueryInstance
): void {
    const state = getAspectState(world, aspect);
    if (type === 'add') state.addedQueries.add(query);
    else if (type === 'remove') state.removedQueries.add(query);
    else state.changedQueries.add(query);
}
